module top_module(input CLK_12M,input EVEN,input LOAD,input H,input [31:0] CR,output reg [3:0] GAD, GBD,output reg DOTA, DOTB);reg [31:0] ZZSR; 
  always @(negedge CLK_12M) 
  begin 
  if (LOAD) ZZSR <= CR; 
  else if (H) ZZSR <= {ZZSR[29:24], 2'b00, ZZSR[21:16], 2'b00, ZZSR[13:8], 2'b00, ZZSR[5:0], 2'b00}; 
  else ZZSR <= {2'b00, ZZSR[31:26], 2'b00, ZZSR[23:18], 2'b00, ZZSR[15:10], 2'b00, ZZSR[7:2]}; 
  end 
  always @* 
  begin 
  case ({EVEN, H}) 
  3: {GBD, GAD} <= {ZZSR[31], ZZSR[23], ZZSR[15], ZZSR[7], ZZSR[30], ZZSR[22], ZZSR[14], ZZSR[6]}; 
  2: {GBD, GAD} <= {ZZSR[24], ZZSR[16], ZZSR[8], ZZSR[0], ZZSR[25], ZZSR[17], ZZSR[9], ZZSR[1]}; 
  1: {GBD, GAD} <= {ZZSR[30], ZZSR[22], ZZSR[14], ZZSR[6], ZZSR[31], ZZSR[23], ZZSR[15], ZZSR[7]}; 
  0: {GBD, GAD} <= {ZZSR[25], ZZSR[17], ZZSR[9], ZZSR[1], ZZSR[24], ZZSR[16], ZZSR[8], ZZSR[0]}; 
  endcase 
  {DOTA, DOTB} <= {|GAD, |GBD}; 
  end 
 endmodule
